fibonacci:
% Function to generate the first N Fibonacci numbers iteratively
function fib_seq = generate_fibonacci(n)
    if ~isscalar(n) || n < 1 || floor(n) ~= n
        error('Input must be a positive integer scalar.');
    end

    if n == 1
        fib_seq = 0;
    else
        fib_seq = zeros(1, n); % Pre-allocate array
        fib_seq(1) = 0;
        fib_seq(2) = 1;
        for i = 3:n
            fib_seq(i) = fib_seq(i-1) + fib_seq(i-2);
        end
    end
end

% Example: Generate first 10 terms
num_terms = 10;
fib_numbers = generate_fibonacci(num_terms);

fprintf('Fibonacci sequence (first %d terms):\n', num_terms);
disp(fib_numbers); % Display the resulting array

% Example: Generate first 1 term
fprintf('Fibonacci sequence (first %d term):\n', 1);
disp(generate_fibonacci(1));

% Example: Generate first 2 terms
fprintf('Fibonacci sequence (first %d terms):\n', 2);
disp(generate_fibonacci(2));

