writeFile:
% Write text content to a file

filename = 'output_matlab.txt';
content_line1 = 'This is the first line written by MATLAB.';
content_line2 = 'This is the second line.';
content_append = 'This line was appended.';

% --- Write mode ('w'): Overwrites or creates file ---
fprintf('--- Writing to "%s" (overwrite mode) ---\n', filename);
try
    fileID = fopen(filename, 'w'); % Open for writing
    if fileID == -1
        error('Cannot open file "%s" for writing.', filename);
    end
    fprintf(fileID, '%s\n', content_line1); % Write first line with newline
    fprintf(fileID, '%s\n', content_line2); % Write second line
    fclose(fileID);                     % Close the file
    fprintf('Successfully wrote initial content.\n');
catch ME
    fprintf('Error during write: %s\n', ME.message);
    if exist('fileID', 'var') && fileID ~= -1; fclose(fileID); end % Ensure close on error
end

% --- Append mode ('a'): Adds to end or creates file ---
fprintf('\n--- Appending to "%s" --- \n', filename);
try
    fileID = fopen(filename, 'a'); % Open for appending
    if fileID == -1
        error('Cannot open file "%s" for appending.', filename);
    end
    fprintf(fileID, '%s\n', content_append); % Append third line
    fclose(fileID);                      % Close the file
    fprintf('Successfully appended content.\n');
catch ME
    fprintf('Error during append: %s\n', ME.message);
    if exist('fileID', 'var') && fileID ~= -1; fclose(fileID); end
end

% --- Display final content ---
fprintf('\n--- Final content of "%s": --- \n', filename);
type(filename); % Display file content in command window

