% delete(filename);

fileExists:
% Check if a file or directory exists using exist()

file_to_check = 'matlab_exists_test.m'; % Use a .m extension for clarity
dir_to_check = 'my_matlab_dir';
non_existent = 'no_such_file_or_dir.abc';

% Create dummy file and directory
try
    fclose(fopen(file_to_check, 'w')); % Create empty file
    mkdir(dir_to_check);
    fprintf('Created dummy file "%s" and directory "%s"\n', file_to_check, dir_to_check);

    fprintf('\n--- Checking existence --- \n');

    % exist() returns:
    % 0: does not exist
    % 2: is a file (includes .m, .mat, MEX, etc.)
    % 7: is a directory
    % other values: built-in function, variable, etc.

    exist_status = exist(file_to_check, 'file'); % Check specifically for file
    fprintf('Does "%s" exist as a file? (exist(..., ''file'')==2): %d -> %s\n', file_to_check, exist_status, string(exist_status==2));

    exist_status = exist(dir_to_check, 'dir');   % Check specifically for directory
    fprintf('Does "%s" exist as a directory? (exist(..., ''dir'')==7): %d -> %s\n', dir_to_check, exist_status, string(exist_status==7));

    exist_status = exist(non_existent, 'file'); % Check non-existent file
    fprintf('Does "%s" exist as a file? (exist(..., ''file'')==2): %d -> %s\n', non_existent, exist_status, string(exist_status==2));

    exist_status = exist(dir_to_check, 'file'); % Check if dir exists as a file
    fprintf('Does "%s" exist as a file? (exist(..., ''file'')==2): %d -> %s\n', dir_to_check, exist_status, string(exist_status==2));

    exist_status = exist(file_to_check, 'dir'); % Check if file exists as a dir
    fprintf('Does "%s" exist as a directory? (exist(..., ''dir'')==7): %d -> %s\n', file_to_check, exist_status, string(exist_status==7));

    % Clean up
    delete(file_to_check);
    rmdir(dir_to_check);
    fprintf('\nCleaned up dummy file and directory.\n');

catch ME
    fprintf('An error occurred: %s\n', ME.message);
    % Attempt cleanup
    if exist(file_to_check, 'file') == 2; delete(file_to_check); end
    if exist(dir_to_check, 'dir') == 7; rmdir(dir_to_check); end
end

dateTime:
% Get and format the current date and time

% Get current date and time as a datetime object
current_dt = datetime('now');
disp('Current datetime object:');
disp(current_dt);

% Format the datetime object using predefined formats
fprintf('\n--- Predefined Formats --- \n');
fprintf('Default: %s\n', datestr(current_dt));
fprintf('ISO 8601 (yyyy-MM-dd''T''HH:mm:ss): %s\n', datestr(current_dt, 'yyyy-mm-ddTHH:MM:SS')); % ISO format requires specifying
fprintf('Short Date (dd-mmm-yyyy): %s\n', datestr(current_dt, 'dd-mmm-yyyy'));
fprintf('Long Date and Time: %s\n', datestr(current_dt, 'dddd, mmmm dd, yyyy HH:MM:SS'));

% Custom format using Format property (for datetime objects)
current_dt.Format = 'yyyy-MM-dd HH:mm:ss.SSS';
fprintf('\nCustom Format (datetime object): %s\n', string(current_dt));

% Get components
[Y, M, D] = ymd(current_dt);
[h, m, s] = hms(current_dt);
fprintf('Components: Year=%d, Month=%d, Day=%d, Hour=%d, Minute=%d, Second=%.2f\n', Y, M, D, h, m, s);

% Unix Epoch Time (Seconds since 1970-01-01 00:00:00 UTC)
% Requires conversion to UTC first if local time is different
% posixtime requires R2015a or later
utc_dt = datetime('now', 'TimeZone', 'UTC');
epoch_time = posixtime(utc_dt); % Returns double
fprintf('Seconds since epoch (UTC): %.0f\n', epoch_time);

maxInArray:
% Find the maximum value in an array (vector or matrix)

% Example 1D array (vector)
my_vector = [10, 5, 42, 17, 8, 99, 32, -5, 0];
disp('Vector:');
disp(my_vector);

% Use the built-in max() function
% For vectors, returns the maximum value
max_val_vector = max(my_vector);
fprintf('Maximum value in vector: %d\n', max_val_vector);

% Find both max value and its index
[max_val_vector_idx, idx] = max(my_vector);
fprintf('Maximum value %d found at index %d\n', max_val_vector_idx, idx);

fprintf('\n'); % Newline separator

% Example 2D array (matrix)
my_matrix = [ 1, 9, 2;
              8, 3, 7;
              4, 6, 5 ];
disp('Matrix:');
disp(my_matrix);

% By default, max() operates along columns
max_per_col = max(my_matrix); % Returns a row vector [8, 9, 7]
disp('Maximum value per column:');
disp(max_per_col);

% To find the maximum across the entire matrix:
max_overall = max(my_matrix, [], 'all'); % R2018b or later
% Alternative for older versions: max(my_matrix(:))
fprintf('Maximum value overall: %d\n', max_overall);

% Find max in each row (operate along dimension 2)
max_per_row = max(my_matrix, [], 2); % Returns a column vector [9; 8; 6]
disp('Maximum value per row:');
disp(max_per_row);
